        type: 'access',
        requestId,
        method: request.method || 'UNKNOWN',
        path: url.pathname,
        statusCode,
        durationMs: Number(durationMs.toFixed(3)),
        remoteAddress: request.socket.remoteAddress || null
      });
    }
  });
}

export async function startServer({
  port = 3000,
  host = '127.0.0.1',
  filePath,
  logger,
  writeToken,
  writeTokenNext
}) {
  const store = new IncrementStore(filePath);
  await store.init();

  const server = createServer({ store, logger, writeToken, writeTokenNext });

  await new Promise((resolve) => {
    server.listen(port, host, resolve);
  });

  return server;
}
