test('GET /v1/increments starts empty then includes created increment', async () => {
  const harness = await startTestServer();

  try {
    const emptyResponse = await fetch(`${harness.baseUrl}/v1/increments`);
    const emptyBody = await emptyResponse.json();
    assert.equal(emptyResponse.status, 200);
    assert.deepEqual(emptyBody.increments, []);
    assert.match(emptyBody.requestId, /^[0-9a-f-]{36}$/i);

    const createResponse = await fetch(`${harness.baseUrl}/v1/increments`, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        title: 'Bootstrap API foundation',
        summary: 'Ship base endpoints with tests',
        owner: 'founding-engineer'
      })
    });

    const createdBody = await createResponse.json();
    assert.equal(createResponse.status, 201);
    assert.equal(createdBody.increment.title, 'Bootstrap API foundation');
    assert.match(createdBody.requestId, /^[0-9a-f-]{36}$/i);

    const listResponse = await fetch(`${harness.baseUrl}/v1/increments`);
    const listBody = await listResponse.json();

    assert.equal(listResponse.status, 200);
    assert.equal(listBody.increments.length, 1);
    assert.equal(listBody.increments[0].summary, 'Ship base endpoints with tests');
    assert.match(listBody.requestId, /^[0-9a-f-]{36}$/i);
  } finally {
    await harness.close();
  }
});

