test('POST /v1/increments enforces bearer token when configured', async () => {
  const harness = await startTestServer({ writeToken: 'secret-token' });

  try {
    const payload = {
      title: 'Protected write',
      summary: 'Should require auth'
    };

    const missingToken = await fetch(`${harness.baseUrl}/v1/increments`, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify(payload)
    });
    assert.equal(missingToken.status, 401);
    assert.match(
      missingToken.headers.get('www-authenticate') || '',
      /^Bearer realm="daio-api"$/
    );

    const wrongToken = await fetch(`${harness.baseUrl}/v1/increments`, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        authorization: 'Bearer wrong-token'
      },
      body: JSON.stringify(payload)
    });
    assert.equal(wrongToken.status, 401);

    const validToken = await fetch(`${harness.baseUrl}/v1/increments`, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        authorization: 'Bearer secret-token'
      },
      body: JSON.stringify(payload)
    });
